/**
 * @summary Get messages for a match
 */
export const getGetMessagesUrl = (
  matchId: number,
  params?: GetMessagesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/chat/${matchId}/messages?${stringifiedParams}`
    : `/api/chat/${matchId}/messages`;
};

export const getMessages = async (
  matchId: number,
  params?: GetMessagesParams,
  options?: RequestInit,
): Promise<Message[]> => {
  return customFetch<Message[]>(getGetMessagesUrl(matchId, params), {
    ...options,
    method: "GET",
  });
};

export const getGetMessagesQueryKey = (
  matchId: number,
  params?: GetMessagesParams,
) => {
  return [
    `/api/chat/${matchId}/messages`,
    ...(params ? [params] : []),
  ] as const;
};

export const getGetMessagesQueryOptions = <
  TData = Awaited<ReturnType<typeof getMessages>>,
  TError = ErrorType<unknown>,
>(
  matchId: number,
  params?: GetMessagesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getMessages>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetMessagesQueryKey(matchId, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getMessages>>> = ({
    signal,
  }) => getMessages(matchId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!matchId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getMessages>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetMessagesQueryResult = NonNullable<
  Awaited<ReturnType<typeof getMessages>>
>;
export type GetMessagesQueryError = ErrorType<unknown>;

